def generate_sugar_label(ragione_sociale, via, cap_citta_provincia, stato, telefono, ca, notes):
    """
    Genera il codice ZPL per l'etichetta Personal Zucchero.
    I campi del mittente sono allineati a destra con margine 50.
    """
    zpl = f"""^XA

^FO620,50^GF{LOGO_DATA}^FS

^FX Inversione assi per formato verticale
^PW800
^LL1198
^LS0

^FX Imposta l'orientamento globale dei campi a 90 gradi (orario)
^FWR

^FX Sezione Superiore: Mittente
^CF0,50
^FO740,50^FB1098,1,0,R^FDPersonal Zucchero SRL^FS
^CF0,25
^FO700,50^FB1098,1,0,R^FDPiazza Allende 1^FS
^FO665,50^FB1098,1,0,R^FD47824 Poggio Torriana RN^FS
^FO630,50^FB1098,1,0,R^FDItaly^FS
^FX La riga orizzontale ^GB1100,3,3 diventa verticale ^GB3,1100,3
^FO580,50^GB3,1100,3^FS

^FX Sezione Centrale: Destinatario e Permit
^CF0,20
^FO530,50^FDRecipient:^FS
^CF0,35
^FO480,60^FD{ragione_sociale}^FS
^FO430,60^FD{via}^FS
^FO380,60^FD{cap_citta_provincia}^FS
^FO330,60^FD{stato}^FS
^FO280,60^FD{telefono}^FS
^FO230,60^FDc.a.: {ca}^FS

^FX Sezione Note
^FO200,50^GB3,1100,3^FS
^CF0,50
^FO130,50^FD{notes}^FS

^XZ"""
    return zpl